#include <stddef.h>
#include <stdint.h>
#include <unistd.h>

int main(void) {
  /* XOR key: 0x55. Encoded bytes only, no plaintext flag in source. */
  uint8_t enc[] = {
      0x06, 0x00, 0x16, 0x01, 0x13, 0x2e, 0x06, 0x26, 0x07, 0x13,
      0x0a, 0x21, 0x1a, 0x0a, 0x27, 0x16, 0x66, 0x0a, 0x37, 0x2c,
      0x0a, 0x31, 0x65, 0x16, 0x3e, 0x10, 0x27, 0x0a, 0x64, 0x60,
      0x0a, 0x26, 0x65, 0x0a, 0x13, 0x00, 0x3b, 0x28,
  };

  for (size_t i = 0; i < sizeof(enc); i++) {
    enc[i] ^= 0x55;
  }

  (void)write(STDOUT_FILENO, enc, sizeof(enc));
  (void)write(STDOUT_FILENO, "\n", 1);
  return 0;
}

